1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Base premium calculations - quote operation
6	  it("quote with empty item list returns premium of 5 (just processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it("quote with a single plain sword returns base premium + fee", () => {
14	    const result = processScenario({
15	      customer: { yearsWithMHPCO: 0 },
16	      steps: [
17	        {
18	          op: "quote",
19	          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
20	        },
21	      ],
22	    });
23	    // 100 base + 10 first insurance (10%) + 5 fee = 115
24	    expect(result).toEqual({ results: [{ premium: 115 }] });
25	  });
26	  it.todo("quote with a single plain amulet returns base premium + fee");
27	  it.todo("quote with a single plain staff returns base premium + fee");
28	  it.todo("quote with a single plain potion returns base premium + fee");
29	
30	  // Components
31	  it.todo("quote with 2 runes returns 50G base + fee (no block)");
32	  it.todo("quote with 3 runes returns 60G base + fee (block applies)");
33	  it.todo("quote with 4 runes returns 100G base + fee (no block)");
34	  it.todo("quote with 7 runes returns 175G base + fee");
35	  it.todo("quote with 2 runes + 1 moonstone returns 75G base + fee (no block, different types)");
36	  it.todo("quote with 3 runes + 3 moonstones returns 120G base + fee (two separate blocks)");
37	
38	  // Item-specific modifiers
39	  it.todo("quote with a cursed sword adds 50% surcharge to sword base premium");
40	  it.todo("quote with a sword enchantment 5 adds 30% high-enchantment surcharge");
41	  it.todo("quote with a sword enchantment 4 does not add high-enchantment surcharge");
42	  it.todo("quote with a cursed sword enchantment 5 adds both surcharges");
43	
44	  // Policy-wide modifiers
45	  it.todo("quote for customer with 2 years gets 20% loyalty discount on policy base");
46	  it.todo("quote applies 10% first insurance surcharge on policy base");
47	  it.todo("quote for customer's second contract applies 15% follow-up discount");
48	
49	  // Multi-item policies - modifier scope
50	  it.todo("quote with cursed sword + plain amulet applies cursed surcharge only to sword");
51	
52	  // Rounding
53	  it.todo("quote rounds final premium up (in MHPCO's favor)");
54	
55	  // Integration examples
56	  it.todo("newcomer with cursed sword (steel, enchantment 3) -> premium 165");
57	  it.todo("long-standing customer's second contract with cursed sword enchantment 7 -> premium 160");
58	
59	  // Claim processing - basic
60	  it.todo("claim with damage 500 on regular sword (no clauses) returns payout 400 (500 - 100 deductible)");
61	  it.todo("claim with damage 200 on a rune returns payout 100 (200 - 100 deductible)");
62	
63	  // Claim - enchantment threshold
64	  it.todo("claim on enchantment 9 sword with damage 1000 returns payout 400 (50% then deductible)");
65	
66	  // Claim - dragon material
67	  it.todo("claim on dragon-material sword damage 800 returns payout 700 (full then deductible)");
68	
69	  // Claim - both clauses
70	  it.todo("claim on dragon-material enchantment 9 sword damage 1000 returns payout 400 (50% wins)");
71	  it.todo("claim on dragon-material enchantment 8 sword damage 1000 returns payout 400");
72	
73	  // Claim - per-damage deductible
74	  it.todo("claim with two damaged items applies deductible per damage event");
75	
76	  // Cap and remaining cap
77	  it.todo("claim returns remainingCap = cap - payout");
78	  it.todo("two successive claims exhaust the cap (1500/1500 on sword: 1400, then 600)");
79	
80	  // CLI scenario with quote then claim
81	  it.todo("scenario with quote followed by claim returns results in order");
82	});
