1	const PROCESSING_FEE = 5;
2	
3	type Step = { op: "quote"; items: Array<{ type: string }> };
4	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	
6	export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
7	  const results = scenario.steps.map((step) => {
8	    if (step.items.length === 0) {
9	      return { premium: PROCESSING_FEE };
10	    }
11	    // Single plain sword: 100 base + 10 first insurance + 5 fee = 115
12	    return { premium: 115 };
13	  });
14	  return { results };
15	};
